import { Node } from 'n8n-workflow';

function detectSequentialAINodes(workflow: any): string[] {
  const aiNodeTypes = ['n8n-nodes-langchain.agent', 'n8n-nodes-langchain.chatModel'];
  const issues: string[] = [];

  workflow.nodes.forEach((node: Node, index: number) => {
    if (aiNodeTypes.includes(node.type)) {
      const nextConnections = workflow.connections[node.id] || [];
      nextConnections.forEach((connection: any[]) => {
        connection.forEach((targetNodeId: string) => {
          const targetNode = workflow.nodes.find((n: Node) => n.id === targetNodeId);
          if (targetNode && aiNodeTypes.includes(targetNode.type)) {
            issues.push(`Sequential AI nodes detected: ${node.name} → ${targetNode.name}`);
          }
        });
      });
    }
  });

  return issues;
}

function detectPromptBloat(aiNode: any): boolean {
  const memoryPatterns = [
    '{{$json.memoryWindow}}',
    '{{$node["Memory"].json["context"]}}',
    '{{$workflow.memory}}'
  ];

  const prompt = aiNode.parameters?.prompt || '';
  const hasMemoryInjection = memoryPatterns.some(pattern => prompt.includes(pattern));

  // Check for large static context
  const staticContextSize = (prompt.match(/\{\{[^}]+\}\}/g) || []).length;
  const tokenEstimate = prompt.length / 4 + staticContextSize * 500;

  return hasMemoryInjection && tokenEstimate > 25000;
}

function detectNoStreaming(aiNodes: any[]): string[] {
  return aiNodes
    .filter(node => !node.parameters?.streaming && !node.parameters?.stream)
    .map(node => `AI Agent '${node.name}' has streaming disabled - full response blocking detected`);
}

