import { Vex } from '@vex_dev/sdk';

const vex = new Vex({
  webhookSecret: process.env.VEX_WEBHOOK_SECRET!,
  projectId: 'n8n-ai-latency-opt'
});

// n8n webhook node code for Vex integration
export async function vexLatencyGuard(inputData: any[]) {
  const workflowData = $workflow.staticData;
  const execution = $execution;

  const analysis = await vex.analyze({
    framework: 'n8n',
    workflowJson: workflowData.workflow,
    aiNodes: execution.nodeData.filter((n: any) => 
      n.node.type.includes('langchain') || n.node.type.includes('agent')
    ),
    metrics: {
      avgLatency: execution.waitingTime,
      tokenUsage: execution.nodeData.reduce((sum: number, n: any) => 
        sum + (n.data?.tokensUsed || 0), 0
      )
    },
    problem: 'llm-latency-agent'
  });

  if (analysis.issues.length > 0) {
    // Auto-apply fixes
    const fixes = await vex.remediate(analysis);
    return [{ json: { optimized: true, fixesApplied: fixes.length } }];
  }

  return inputData;
}
